vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame

    // darken (decay) over uTime
//    ret *= 0.5; //or try: ret -= 0.004;
ret = tex2d(sampler_rand00,vUv);//-ret;
//ret *= 0.795; //or try: ret -= 0.004;

ret = tex2d(sampler_rand00,vUvOriginal)-ret;
//ret *= .95; //or try: ret -= 0.004;
//ret = texture( sampler_main, vUv ).xyz-ret;
//ret *= 0.95; //or try: ret -= 0.004;
ret=GetBlur3 (vUv)-ret;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float qrad=((1-vRadius)-1/max(audioLow,audioLowSmooth));
float tim=q17;//uTime/(9+(1/(.5+max(.5,audioMidSmooth))));
vec3 pre = texture(sampler_main, vUv).xyz;
    vec2 pix = uTexSize.zw;
    vec3 myblur  = pre*3;
           myblur += texture(sampler_main, vUv + vec2(-1,-1)*pix)*0.75;
           myblur += texture(sampler_main, vUv + vec2( 1, 1)*pix)*0.75;
           myblur += texture(sampler_main, vUv + vec2( 1,-1)*pix)*0.75;
           myblur += texture(sampler_main, vUv + vec2(-1, 1)*pix)*0.75;
           myblur += texture(sampler_main, vUv + vec2( 0,-1)*pix);
           myblur += texture(sampler_main, vUv + vec2( 0, 1)*pix);
           myblur += texture(sampler_main, vUv + vec2(-1, 0)*pix);
           myblur += texture(sampler_main, vUv + vec2( 1, 0)*pix);
    myblur*=0.1;
    vec3 pre3 = myblur*myblur*myblur;//pre*pre*pre;
    ret = pre3;//pre*pre*pre;
tim-=int(tim);
tim=(max(tim,1-tim)-.5)*2-.51*cos(qrad);
ret+=pre;
ret+=.391*tex2d(sampler_fc_rand00,mix(vec2(max((vUv.x*(1-vUv.x)),(1-vUv.x)*vUv.x)-2+.5*sin(qrad),vUv.y),
vec2(max(vUvOriginal.x*(1-vUvOriginal.x),(1-vUvOriginal.x)*vUvOriginal.x)-.25,vUvOriginal.y),max(ret,1-ret)-(.25-.071*vUv.x)*cos(tim))+vec2(.5+.1*sin(tim),0)).xyz;

  fragColor = ret;
}
